94	/// Opaque type tracking the amount of "work" a task may still do before
95	/// yielding back to the scheduler.
96	#[derive(Debug, Copy, Clone)]
97	pub(crate) struct Budget(Option<u8>);
98	
99	pub(crate) struct BudgetDecrement {
100	    success: bool,
101	    hit_zero: bool,
102	}
