465	impl Handle {
466	    /// Spawns a future onto the `CurrentThread` scheduler
467	    #[track_caller]
468	    pub(crate) fn spawn<F>(
469	        me: &Arc<Self>,
470	        future: F,
471	        id: crate::runtime::task::Id,
472	        spawned_at: SpawnLocation,
473	    ) -> JoinHandle<F::Output>
474	    where
475	        F: crate::future::Future + Send + 'static,
476	        F::Output: Send + 'static,
477	    {
478	        let (handle, notified) = me.shared.owned.bind(future, me.clone(), id, spawned_at);
479	
480	        me.task_hooks.spawn(&TaskMeta {
481	            id,
482	            spawned_at,
483	            _phantom: Default::default(),
484	        });
485	
486	        if let Some(notified) = notified {
487	            me.schedule(notified);
488	        }
489	
490	        handle
491	    }
492	
493	    /// Spawn a task which isn't safe to send across thread boundaries onto the runtime.
494	    ///
495	    /// # Safety
496	    ///
497	    /// This should only be used when this is a `LocalRuntime` or in another case where the runtime
498	    /// provably cannot be driven from or moved to different threads from the one on which the task
499	    /// is spawned.
500	    #[track_caller]
501	    pub(crate) unsafe fn spawn_local<F>(
502	        me: &Arc<Self>,
503	        future: F,
504	        id: crate::runtime::task::Id,
505	        spawned_at: SpawnLocation,
506	    ) -> JoinHandle<F::Output>
507	    where
508	        F: crate::future::Future + 'static,
509	        F::Output: 'static,
510	    {
511	        // Safety: the caller guarantees that this is only called on a `LocalRuntime`.
512	        let (handle, notified) = unsafe {
513	            me.shared
514	                .owned
515	                .bind_local(future, me.clone(), id, spawned_at)
516	        };
517	
518	        me.task_hooks.spawn(&TaskMeta {
519	            id,
520	            spawned_at,
521	            _phantom: Default::default(),
522	        });
523	
524	        if let Some(notified) = notified {
525	            me.schedule(notified);
526	        }
527	
528	        handle
529	    }
530	
531	    /// Capture a snapshot of this runtime's state.
532	    #[cfg(all(
533	        tokio_unstable,
534	        feature = "taskdump",
535	        target_os = "linux",
536	        any(
537	            target_arch = "aarch64",
538	            target_arch = "x86",
539	            target_arch = "x86_64",
540	            target_arch = "s390x"
541	        )
542	    ))]
543	    pub(crate) fn dump(&self) -> crate::runtime::Dump {
544	        use crate::runtime::dump;
545	        use task::trace::trace_current_thread;
546	
547	        let mut traces = vec![];
548	
549	        // todo: how to make this work outside of a runtime context?
550	        context::with_scheduler(|maybe_context| {
551	            // drain the local queue
552	            let context = if let Some(context) = maybe_context {
553	                context.expect_current_thread()
554	            } else {
555	                return;
556	            };
557	            let mut maybe_core = context.core.borrow_mut();
558	            let core = if let Some(core) = maybe_core.as_mut() {
559	                core
560	            } else {
561	                return;
562	            };
563	            let local = &mut core.tasks;
564	
565	            if self.shared.inject.is_closed() {
566	                return;
567	            }
568	
569	            traces = trace_current_thread(&self.shared.owned, local, &self.shared.inject)
570	                .into_iter()
571	                .map(|(id, trace)| dump::Task::new(id, trace))
572	                .collect();
573	
574	            // Avoid double borrow panic
575	            drop(maybe_core);
576	
577	            // Taking a taskdump could wakes every task, but we probably don't want
578	            // the `yield_now` vector to be that large under normal circumstances.
579	            // Therefore, we free its allocation.
580	            wake_deferred_tasks_and_free(context);
581	        });
582	
583	        dump::Dump::new(traces)
584	    }
