666	impl Schedule for Arc<Handle> {
667	    fn release(&self, task: &Task<Self>) -> Option<Task<Self>> {
668	        self.shared.owned.remove(task)
669	    }
670	
671	    fn schedule(&self, task: task::Notified<Self>) {
672	        use scheduler::Context::CurrentThread;
673	
674	        context::with_scheduler(|maybe_cx| match maybe_cx {
675	            Some(CurrentThread(cx)) if Arc::ptr_eq(self, &cx.handle) => {
676	                let mut core = cx.core.borrow_mut();
677	
678	                // If `None`, the runtime is shutting down, so there is no need
679	                // to schedule the task.
680	                if let Some(core) = core.as_mut() {
681	                    core.push_task(self, task);
682	                }
683	            }
684	            _ => {
685	                // Track that a task was scheduled from **outside** of the runtime.
686	                self.shared.scheduler_metrics.inc_remote_schedule_count();
687	
688	                // Schedule the task
689	                self.shared.inject.push(task);
690	                self.driver.unpark();
691	            }
692	        });
693	    }
694	
695	    fn hooks(&self) -> TaskHarnessScheduleHooks {
696	        TaskHarnessScheduleHooks {
697	            task_terminate_callback: self.task_hooks.task_terminate_callback.clone(),
698	        }
699	    }
