701	    cfg_unstable! {
702	        fn unhandled_panic(&self) {
703	            use crate::runtime::UnhandledPanic;
704	
705	            match self.shared.config.unhandled_panic {
706	                UnhandledPanic::Ignore => {
707	                    // Do nothing
708	                }
709	                UnhandledPanic::ShutdownRuntime => {
710	                    use scheduler::Context::CurrentThread;
711	
712	                    // This hook is only called from within the runtime, so
713	                    // `context::with_scheduler` should match with `&self`, i.e.
714	                    // there is no opportunity for a nested scheduler to be
715	                    // called.
716	                    context::with_scheduler(|maybe_cx| match maybe_cx {
717	                        Some(CurrentThread(cx)) if Arc::ptr_eq(self, &cx.handle) => {
718	                            let mut core = cx.core.borrow_mut();
