739	    /// Wake by reference
740	    fn wake_by_ref(arc_self: &Arc<Self>) {
741	        let already_woken = arc_self.shared.woken.swap(true, Release);
742	
743	        if !already_woken {
744	            use scheduler::Context::CurrentThread;
745	
746	            // If we are already running on the runtime, then it's not required to wake up the
747	            // runtime.
748	            context::with_scheduler(|maybe_cx| match maybe_cx {
749	                Some(CurrentThread(cx)) if Arc::ptr_eq(arc_self, &cx.handle) => {}
750	                _ => {
751	                    arc_self.driver.unpark();
752	                }
753	            });
754	        }
755	    }
