760	/// Used to ensure we always place the `Core` value back into its slot in
761	/// `CurrentThread`, even if the future panics.
762	struct CoreGuard<'a> {
763	    context: scheduler::Context,
764	    scheduler: &'a CurrentThread,
765	}
766	
767	impl CoreGuard<'_> {
768	    #[track_caller]
769	    fn block_on<F: Future>(self, future: F) -> F::Output {
770	        let ret = self.enter(|mut core, context| {
771	            let waker = Handle::waker_ref(&context.handle);
772	            let mut cx = std::task::Context::from_waker(&waker);
773	
774	            pin!(future);
775	
776	            core.metrics.start_processing_scheduled_tasks();
777	
778	            'outer: loop {
779	                let handle = &context.handle;
780	
781	                if handle.reset_woken() {
782	                    let (c, res) = context.enter(core, || {
783	                        crate::task::coop::budget(|| future.as_mut().poll(&mut cx))
784	                    });
785	
786	                    core = c;
787	
788	                    if let Ready(v) = res {
789	                        return (core, Some(v));
790	                    }
791	                }
792	
793	                for _ in 0..handle.shared.config.event_interval {
794	                    // Make sure we didn't hit an unhandled_panic
795	                    if core.unhandled_panic {
796	                        return (core, None);
797	                    }
798	
799	                    core.tick();
