211	    fn poll(self: Pin<&mut Self>, cx: &mut task::Context<'_>) -> Poll<Self::Output> {
212	        let me = self.project();
213	
214	        let had_budget_before = coop::has_budget_remaining();
215	
216	        // First, try polling the future
217	        if let Poll::Ready(v) = me.value.poll(cx) {
218	            return Poll::Ready(Ok(v));
219	        }
220	
221	        poll_delay(had_budget_before, me.delay, cx).map(Err)
222	    }
223	}
