225	// The T-invariant portion of Timeout::<T>::poll. Pulling this out reduces the
226	// amount of code that gets duplicated during monomorphization.
227	fn poll_delay(
228	    had_budget_before: bool,
229	    delay: Pin<&mut Sleep>,
230	    cx: &mut task::Context<'_>,
231	) -> Poll<Elapsed> {
232	    let delay_poll = || match delay.poll(cx) {
233	        Poll::Ready(()) => Poll::Ready(Elapsed::new()),
234	        Poll::Pending => Poll::Pending,
235	    };
236	
237	    let has_budget_now = coop::has_budget_remaining();
238	
239	    if let (true, false) = (had_budget_before, has_budget_now) {
240	        // if it is the underlying future that exhausted the budget, we poll
241	        // the `delay` with an unconstrained one. This prevents pathological
242	        // cases where the underlying future always exhausts the budget and
